<?php require_once __DIR__.'/includes/functions.php';if($_SERVER['REQUEST_METHOD']==='POST'){check_csrf();$s=db()->prepare("SELECT * FROM users WHERE email=? AND status='Active'");$s->execute([$_POST['email']]);$u=$s->fetch();if($u&&password_verify($_POST['password'],$u['password_hash'])){$_SESSION['user_id']=$u['id'];redirect('/member/index.php');}flash('error','Invalid login');redirect('/login.php');}include __DIR__.'/includes/header.php';?><section class="section"><h1>Member Login</h1><form class="card form" method="post"><input type="hidden" name="csrf" value="<?=csrf_token()?>"><label>Email<input name="email" type="email"></label><label>Password<input name="password" type="password"></label><button>Login</button><p><a href="<?=BASE_URL?>/forgot-password.php">Forgot password?</a></p></form></section><?php include __DIR__.'/includes/footer.php'; ?>